#include <stdio.h>
#include <stdlib.h>
#define MAX_N 1000000
#define MAX_K 1000000
#define MAX_S 1000000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int managers[N + 1];
        for (int i = 2; i <= N; i++) {
            scanf("%d", &managers[i]);
        }
        int client_lists[K][MAX_S + 1];
        for (int i = 0; i < K; i++) {
            int size;
            scanf("%d", &size);
            client_lists[i][0] = size;
            for (int j = 1; j <= size; j++) {
                scanf("%d", &client_lists[i][j]);
            }
        }
        // Find the minimum vertex cover
        int vertex_cover[N + 1] = {0};
        int count = 0;
        for (int i = 0; i < K; i++) {
            int max_degree = 0;
            int max_degree_node = 0;
            for (int j = 1; j <= client_lists[i][0]; j++) {
                int node = client_lists[i][j];
                if (vertex_cover[node] == 0 && max_degree < client_lists[i][0]) {
                    max_degree = client_lists[i][0];
                    max_degree_node = node;
                }
            }
            if (max_degree_node != 0) {
                vertex_cover[max_degree_node] = 1;
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

