                clientLists[i][0] = size;
                for (int j = 1; j <= size; j++) {
                    clientLists[i][j] = scanner.nextInt();
                }
            }
            // Find the minimum vertex cover
            int[] vertexCover = new int[N + 1];
            int count = 0;
            for (int i = 0; i < K; i++) {
                int maxDegree = 0;
                int maxDegreeNode = 0;
                for (int j = 1; j <= clientLists[i][0]; j++) {
                    int node = clientLists[i][j];
                    if (vertexCover[node] == 0 && maxDegree < clientLists[i][0]) {
